 1→import { type ReactNode } from 'react';
 2→import './command_palette.scss';
 3→
 4→interface CommandPaletteProps {
 5→  children: ReactNode;
 6→}
 7→
 8→export function CommandPalette({ children }: CommandPaletteProps) {
 9→  return (
10→    <div className="command-palette-overlay">
11→      <div className="command-palette">{children}</div>
12→    </div>
13→  );
